import { useEffect, useState } from 'react';
import { Users, Package, ShoppingCart, TrendingUp, Clock, CheckCircle, XCircle } from 'lucide-react';
import { userService, productService, orderService } from '../services/api';
import { StatCard, PageLoader, StatusBadge } from '../components/UI';
import { useAuth } from '../context/AuthContext';

export const DashboardPage = () => {
  const { user } = useAuth();
  const [stats, setStats]   = useState({ users: 0, products: 0, orders: 0, pending: 0 });
  const [orders, setOrders] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const load = async () => {
      try {
        const [usersRes, productsRes, ordersRes] = await Promise.all([
          userService.getAll(),
          productService.getAll(),
          orderService.getAll(),
        ]);
        const allOrders = ordersRes.data;
        setStats({
          users:    usersRes.data.length,
          products: productsRes.data.length,
          orders:   allOrders.length,
          pending:  allOrders.filter(o => o.status === 'Pending').length,
        });
        // 5 orders mới nhất
        setOrders([...allOrders].reverse().slice(0, 5));
      } catch (err) {
        console.error(err);
      } finally {
        setLoading(false);
      }
    };
    load();
  }, []);

  if (loading) return <PageLoader />;

  const hour = new Date().getHours();
  const greeting = hour < 12 ? 'Chào buổi sáng' : hour < 18 ? 'Chào buổi chiều' : 'Chào buổi tối';

  return (
    <div className="space-y-8 animate-slide-up">
      {/* Header */}
      <div>
        <h1 className="text-2xl font-bold text-slate-100">
          {greeting}, {user?.name}! 👋
        </h1>
        <p className="text-slate-500 mt-1">Đây là tổng quan hệ thống hôm nay.</p>
      </div>

      {/* Stats */}
      <div className="grid grid-cols-2 lg:grid-cols-4 gap-4">
        <StatCard icon={Users}        label="Tổng Users"    value={stats.users}    color="bg-blue-500/10 text-blue-400" />
        <StatCard icon={Package}      label="Sản phẩm"      value={stats.products} color="bg-purple-500/10 text-purple-400" />
        <StatCard icon={ShoppingCart} label="Tổng Orders"   value={stats.orders}   color="bg-green-500/10 text-green-400" />
        <StatCard icon={Clock}        label="Chờ xử lý"     value={stats.pending}  color="bg-yellow-500/10 text-yellow-400" />
      </div>

      {/* Recent Orders */}
      <div className="card">
        <div className="flex items-center justify-between mb-6">
          <h2 className="text-lg font-bold text-slate-100">Orders gần đây</h2>
          <span className="text-xs text-slate-500 bg-slate-800 px-3 py-1 rounded-full">5 mới nhất</span>
        </div>

        {orders.length === 0 ? (
          <p className="text-slate-500 text-center py-8">Chưa có order nào</p>
        ) : (
          <div className="space-y-3">
            {orders.map(order => (
              <div key={order.id} className="flex items-center justify-between p-4 bg-slate-900/50 rounded-xl border border-slate-800 hover:border-slate-700 transition-colors">
                <div className="flex items-center gap-4">
                  <div className="w-10 h-10 rounded-xl bg-brand-600/20 flex items-center justify-center">
                    <ShoppingCart className="w-5 h-5 text-brand-400" />
                  </div>
                  <div>
                    <p className="text-sm font-medium text-slate-200">
                      Order #{order.id} — {order.product?.name || 'N/A'}
                    </p>
                    <p className="text-xs text-slate-500">
                      {order.user?.name || 'N/A'} • {order.quantity} sản phẩm
                    </p>
                  </div>
                </div>
                <div className="flex items-center gap-4">
                  <span className="text-sm font-semibold text-slate-200">
                    {order.totalPrice?.toLocaleString('vi-VN')}đ
                  </span>
                  <StatusBadge status={order.status} />
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
};
